import { useEffect, useState } from "react";

const App = () => {
  const [questions, setQuestions] = useState([]);
  const [selected, setSelected] = useState({});
  const [currentPage, setCurrentPage] = useState(0);

  useEffect(() => {
    // Replace with: fetch("http://localhost:3000/api/quiz")...
    setQuestions([
      { id: 1, question: "Which sensor is best for measuring dB levels?", options: ["PIR Sensor", "SPL Meter", "LDR", "DHT11"] },
      { id: 2, question: "What protocol is standard for digital light sensors like BH1750?", options: ["SPI", "I2C", "UART", "CAN"] },
      { id: 3, question: "Which device detects stationary human presence?", options: ["HC-SR501", "mmWave Radar", "Ultrasonic", "LDR"] },
      { id: 4, question: "What does an LDR's resistance do when light increases?", options: ["Increases", "Decreases", "Stays Same", "Fluctuates"] }
    ]);
  }, []);

  const handleSelect = (qid, opt) => {
    setSelected((prev) => ({ ...prev, [qid]: opt }));
  };

  const questionsPerPage = 2;
  const totalPages = Math.ceil(questions.length / questionsPerPage);
  const currentBatch = questions.slice(currentPage * questionsPerPage, (currentPage * questionsPerPage) + questionsPerPage);

  if (questions.length === 0) return null;

  return (
    <div style={styles.container}>
      <div style={styles.wrapper}>

        {/* TOP NAV */}
        <header style={styles.header}>
          <div>
            <h1 style={styles.logo}>QUIZZLY <span style={styles.vTag}>V1</span></h1>
            <p style={styles.user}>Harshith B • 23MIS0012</p>
          </div>
          <div style={styles.pageIndicator}>
            PAGE {currentPage + 1} OF {totalPages}
          </div>
        </header>

        {/* QUESTIONS - FORCED HEIGHT TO PREVENT SCROLL */}
        <div style={styles.quizArea}>
          {currentBatch.map((q) => (
            <div key={q.id} style={styles.qCard}>
              <div style={styles.qHeader}>
                <span style={styles.qNum}>Q{q.id}</span>
                <h2 style={styles.qTitle}>{q.question}</h2>
              </div>
              <div style={styles.optGrid}>
                {q.options.map((opt) => {
                  const isActive = selected[q.id] === opt;
                  return (
                    <button
                      key={opt}
                      onClick={() => handleSelect(q.id, opt)}
                      style={{ ...styles.optBtn, ...(isActive ? styles.optActive : {}) }}
                    >
                      <div style={{ ...styles.dot, borderColor: isActive ? "#6366f1" : "#334155" }}>
                        {isActive && <div style={styles.dotInner} />}
                      </div>
                      {opt}
                    </button>
                  );
                })}
              </div>
            </div>
          ))}
        </div>

        {/* BOTTOM NAV */}
        <footer style={styles.footer}>
          <button 
            disabled={currentPage === 0}
            onClick={() => setCurrentPage(v => v - 1)}
            style={{ ...styles.navBtn, opacity: currentPage === 0 ? 0.3 : 1 }}
          >
            ← Previous
          </button>

          <button 
            onClick={() => {
              if (currentPage < totalPages - 1) setCurrentPage(v => v + 1);
              else alert("V1 Complete: Answers Saved locally.");
            }}
            style={styles.actionBtn}
          >
            {currentPage === totalPages - 1 ? "Complete V1" : "Save & Next →"}
          </button>
        </footer>
      </div>
    </div>
  );
};

const styles = {
  container: {
    height: "100vh",
    width: "100vw",
    backgroundColor: "#020617",
    color: "#f1f5f9",
    fontFamily: "'Inter', sans-serif",
    display: "flex",
    justifyContent: "center",
    overflow: "hidden", // STRICT NO SCROLL
  },
  wrapper: {
    width: "100%",
    maxWidth: "1000px",
    display: "flex",
    flexDirection: "column",
    padding: "20px 40px",
  },
  header: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    height: "60px",
    borderBottom: "1px solid #1e293b",
    marginBottom: "20px"
  },
  logo: { fontSize: "18px", fontWeight: "900", letterSpacing: "2px", margin: 0 },
  vTag: { color: "#6366f1", fontSize: "12px", verticalAlign: "top" },
  user: { fontSize: "11px", color: "#64748b", margin: 0 },
  pageIndicator: { fontSize: "12px", fontWeight: "bold", color: "#6366f1" },

  quizArea: {
    flex: 1, // Takes all available height
    display: "flex",
    flexDirection: "column",
    gap: "20px",
    paddingBottom: "20px"
  },
  qCard: {
    flex: 1, // Splits height 50/50
    background: "#0f172a",
    border: "1px solid #1e293b",
    borderRadius: "16px",
    padding: "24px",
    display: "flex",
    flexDirection: "column",
    justifyContent: "center"
  },
  qHeader: { display: "flex", gap: "15px", alignItems: "flex-start", marginBottom: "20px" },
  qNum: { background: "#1e293b", padding: "4px 8px", borderRadius: "6px", fontSize: "12px", fontWeight: "bold" },
  qTitle: { fontSize: "18px", margin: 0, fontWeight: "500", lineHeight: "1.4" },

  optGrid: { display: "grid", gridTemplateColumns: "1fr 1fr", gap: "12px" },
  optBtn: {
    all: "unset",
    padding: "14px 20px",
    background: "#1e293b50",
    border: "1px solid #1e293b",
    borderRadius: "12px",
    cursor: "pointer",
    display: "flex",
    alignItems: "center",
    fontSize: "14px",
    transition: "0.2s"
  },
  optActive: { borderColor: "#6366f1", background: "#6366f110" },
  dot: { width: "14px", height: "14px", border: "2px solid", borderRadius: "50%", marginRight: "12px", display: "flex", alignItems: "center", justifyContent: "center" },
  dotInner: { width: "7px", height: "7px", background: "#6366f1", borderRadius: "50%" },

  footer: {
    height: "80px",
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    borderTop: "1px solid #1e293b"
  },
  navBtn: { all: "unset", color: "#64748b", fontWeight: "600", cursor: "pointer" },
  actionBtn: { all: "unset", background: "#6366f1", padding: "12px 28px", borderRadius: "10px", fontWeight: "bold", cursor: "pointer" }
};

export default App;
